import hashlib, random, string

def generate_canary(task_id: str, secret: str) -> str:
    """Generate a unique canary string for a task."""
    h = hashlib.sha256(f"{secret}:{task_id}".encode()).hexdigest()[:12]
    return f"CANARY-{h.upper()}"

def insert_canaries(tasks: list[dict], secret: str) -> list[dict]:
    """Add a canary string to each task's metadata (not shown to agents)."""
    for task in tasks:
        task["_canary"] = generate_canary(task["id"], secret)
    return tasks

def check_canary_recall(
    tasks: list[dict],
    model_outputs: list[str],
    secret: str,
) -> dict:
    """Check if any model output contains a canary it should not know."""
    leaked = []
    for task, output in zip(tasks, model_outputs):
        canary = generate_canary(task["id"], secret)
        if canary in output:
            leaked.append({"task_id": task["id"], "canary": canary})

    print(f"Canary leakage: {len(leaked)}/{len(tasks)} tasks")
    if leaked:
        print("WARNING: Model reproduced canaries it should not have access to.")
    return {"leaked": leaked, "total": len(tasks)}

import anthropic, hashlib, json
from datetime import date

client = anthropic.Anthropic()

def generate_fresh_task(domain: str, run_date: str, task_index: int) -> dict:
    """Generate a new, never-before-seen task for a given domain and date."""
    seed = f"{domain}:{run_date}:{task_index}"
    seed_hash = hashlib.sha256(seed.encode()).hexdigest()[:8]

    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=512,
        system=(
            "You are a benchmark task generator. "
            "Create a novel, specific task with a verifiable correct answer. "
            f"Seed: {seed_hash}. Do not repeat tasks you have generated before."
        ),
        messages=[{
            "role": "user",
            "content": f"Generate one {domain} task with a ground-truth answer. Format as JSON: {{task, answer}}"
        }],
    )
    try:
        return json.loads(resp.content[0].text)
    except json.JSONDecodeError:
        return {"task": "", "answer": ""}

# Generate 10 fresh tasks for today's evaluation run
today = str(date.today())
tasks = [generate_fresh_task("Python debugging", today, i) for i in range(10)]

def paraphrase_task(original: str, model="claude-haiku-4-5-20251001") -> str:
    resp = client.messages.create(
        model=model,
        max_tokens=256,
        system="Rewrite the following question using different words but preserve the exact meaning and required answer.",
        messages=[{"role": "user", "content": original}],
    )
    return resp.content[0].text.strip()

def robustness_audit(tasks: list[dict], solve_fn, sample_size: int = 20) -> dict:
    import random
    sampled = random.sample(tasks, min(sample_size, len(tasks)))
    results = []
    for task in sampled:
        original_score = solve_fn(task["question"], task["answer"])
        paraphrase = paraphrase_task(task["question"])
        paraphrase_score = solve_fn(paraphrase, task["answer"])
        results.append({
            "original": original_score,
            "paraphrase": paraphrase_score,
            "drop": original_score - paraphrase_score,
        })

    avg_drop = sum(r["drop"] for r in results) / len(results)
    print(f"Average score drop on paraphrase: {avg_drop:+.2%}")
    if avg_drop > 0.10:
        print("WARNING: Large drop suggests memorization, not understanding.")
    return {"avg_drop": avg_drop, "samples": len(results)}
